import { uuidv7 } from '@motivation/shared';
import type { MealType } from '@motivation/shared';

/**
 * IndexedDB queue for async AI-estimate submits pending delivery to the server.
 * Story 221.
 *
 * The PWA persists a submit here *before* touching the network so it survives
 * being offline and the app closing; a drain (`estimate-submit-shipping.ts`)
 * ships it on reconnect / Background Sync / next open. Its own database, for
 * the same reasons as the image-upload queue (story 124): the OPFS SQLite
 * replica is wiped on snapshot import, and the SW's `sync` handler can't reach
 * the Worker DB.
 *
 * Self-contained: a photo submit carries the original image BYTES here rather
 * than riding the image-upload queue — that queue deletes an entry the instant
 * it broadcasts success, so a submit that missed the broadcast (image shipped
 * by the SW while the app was closed) could never recover its `image_path`.
 * Here the drain uploads the image itself and persists the returned path, so a
 * re-drain never re-uploads.
 *
 * `id` is the `client_submit_id` sent to the server: a repeat POST of the same
 * id resolves to the existing job (migration 029) — one submit is one job.
 */

const DB_NAME = 'motivation-estimate-submits';
const DB_VERSION = 1;
const STORE = 'entries';
const INDEX_STATUS = 'status';

export type EstimateSubmitStatus = 'pending' | 'submitted';

/**
 * Stored shape — image bytes live as an ArrayBuffer with the MIME type beside
 * them (fake-indexeddb does not preserve Blob instances across put/get; real
 * reconstruction is cheap). Empty strings, not null, are the "not set" sentinel
 * so the `status` index and cursor reads stay simple.
 */
interface StoredEstimateSubmit {
    id: string;
    description: string;
    date: string;
    meal_type: MealType;
    image_bytes: ArrayBuffer | null;
    image_mime: string;
    image_filename: string;
    image_path: string;
    status: EstimateSubmitStatus;
    server_job_id: string;
    enqueued_at: string;
    submitted_at: string;
}

export interface EstimateSubmitEntry {
    id: string;
    description: string;
    date: string;
    meal_type: MealType;
    /** Original bytes to upload, present until an image has been uploaded (or for text-only submits: null). */
    image: { blob: Blob; filename: string } | null;
    /** Server image_path once the image is uploaded. Empty until then / for text-only. */
    image_path: string;
    status: EstimateSubmitStatus;
    /** Server estimate-job id once submitted. Empty while pending. */
    server_job_id: string;
    enqueued_at: string;
    submitted_at: string;
}

function toEntry(stored: StoredEstimateSubmit): EstimateSubmitEntry {
    return {
        id: stored.id,
        description: stored.description,
        date: stored.date,
        meal_type: stored.meal_type,
        image: stored.image_bytes
            ? { blob: new Blob([stored.image_bytes], { type: stored.image_mime || 'application/octet-stream' }), filename: stored.image_filename || 'meal.jpg' }
            : null,
        image_path: stored.image_path,
        status: stored.status,
        server_job_id: stored.server_job_id,
        enqueued_at: stored.enqueued_at,
        submitted_at: stored.submitted_at,
    };
}

let dbPromise: Promise<IDBDatabase> | null = null;

function getDb(): Promise<IDBDatabase> {
    if (!dbPromise) dbPromise = open();
    return dbPromise;
}

function open(): Promise<IDBDatabase> {
    return new Promise((resolve, reject) => {
        const req = indexedDB.open(DB_NAME, DB_VERSION);
        req.onupgradeneeded = () => {
            const db = req.result;
            if (!db.objectStoreNames.contains(STORE)) {
                const store = db.createObjectStore(STORE, { keyPath: 'id' });
                store.createIndex(INDEX_STATUS, 'status', { unique: false });
            }
        };
        req.onsuccess = () => resolve(req.result);
        req.onerror = () => reject(req.error ?? new Error('Failed to open estimate-submit IndexedDB'));
    });
}

function awaitTx(tx: IDBTransaction): Promise<void> {
    return new Promise((resolve, reject) => {
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error ?? new Error('IndexedDB transaction failed'));
        tx.onabort = () => reject(tx.error ?? new Error('IndexedDB transaction aborted'));
    });
}

// Mirrors image-upload-store's helper: jsdom's older Blob has no arrayBuffer().
async function blobToArrayBuffer(blob: Blob): Promise<ArrayBuffer> {
    if (typeof (blob as Blob & { arrayBuffer?: unknown }).arrayBuffer === 'function') {
        return blob.arrayBuffer();
    }
    return new Promise<ArrayBuffer>((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
            if (reader.result instanceof ArrayBuffer) resolve(reader.result);
            else reject(new Error('FileReader did not return ArrayBuffer'));
        };
        reader.onerror = () => reject(reader.error ?? new Error('Failed to read blob'));
        reader.readAsArrayBuffer(blob);
    });
}

export interface EnqueueEstimateSubmitInput {
    description?: string;
    date: string;
    meal_type: MealType;
    /** Raw image bytes to upload in the drain. Null/omit for a text-only submit. */
    image?: { blob: Blob; filename: string } | null;
    /** A pre-uploaded image_path (re-estimate of an already-uploaded photo). */
    image_path?: string;
}

/** Persist a submit and return its `client_submit_id`. Status starts `pending`. */
export async function enqueueEstimateSubmit(input: EnqueueEstimateSubmitInput): Promise<string> {
    const id = uuidv7();
    const image = input.image ?? null;
    const stored: StoredEstimateSubmit = {
        id,
        description: input.description ?? '',
        date: input.date,
        meal_type: input.meal_type,
        image_bytes: image ? await blobToArrayBuffer(image.blob) : null,
        image_mime: image?.blob.type ?? '',
        image_filename: image?.filename ?? '',
        image_path: input.image_path ?? '',
        status: 'pending',
        server_job_id: '',
        enqueued_at: Temporal.Now.instant().toString(),
        submitted_at: '',
    };
    const db = await getDb();
    const tx = db.transaction(STORE, 'readwrite');
    tx.objectStore(STORE).put(stored);
    await awaitTx(tx);
    return id;
}

/** Oldest-first pending submits — the drain ships these. */
export async function getPendingEstimateSubmits(limit = 25): Promise<EstimateSubmitEntry[]> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readonly');
    const index = tx.objectStore(STORE).index(INDEX_STATUS);
    const out: EstimateSubmitEntry[] = [];
    return new Promise((resolve, reject) => {
        const req = index.openCursor(IDBKeyRange.only('pending'));
        req.onsuccess = () => {
            const cursor = req.result;
            if (!cursor || out.length >= limit) {
                out.sort((a, b) => a.enqueued_at.localeCompare(b.enqueued_at));
                resolve(out);
                return;
            }
            out.push(toEntry(cursor.value as StoredEstimateSubmit));
            cursor.continue();
        };
        req.onerror = () => reject(req.error ?? new Error('Failed to read estimate-submit queue'));
    });
}

/** Look up one submit by its `client_submit_id`; null if absent. Used by the review screen. */
export async function getEstimateSubmit(id: string): Promise<EstimateSubmitEntry | null> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readonly');
    const req = tx.objectStore(STORE).get(id);
    return new Promise((resolve, reject) => {
        req.onsuccess = () => {
            const row = req.result as StoredEstimateSubmit | undefined;
            resolve(row ? toEntry(row) : null);
        };
        req.onerror = () => reject(req.error ?? new Error('Failed to read estimate-submit row'));
    });
}

async function mutate(id: string, apply: (row: StoredEstimateSubmit) => void): Promise<void> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readwrite');
    const store = tx.objectStore(STORE);
    const getReq = store.get(id);
    await new Promise<void>((resolve, reject) => {
        getReq.onsuccess = () => {
            const row = getReq.result as StoredEstimateSubmit | undefined;
            if (!row) { resolve(); return; }
            apply(row);
            const putReq = store.put(row);
            putReq.onsuccess = () => resolve();
            putReq.onerror = () => reject(putReq.error ?? new Error('Failed to update estimate-submit row'));
        };
        getReq.onerror = () => reject(getReq.error ?? new Error('Failed to read estimate-submit row'));
    });
    await awaitTx(tx);
}

/** Record the uploaded image path and drop the now-redundant bytes (so a re-drain never re-uploads). */
export async function setEstimateSubmitImagePath(id: string, imagePath: string): Promise<void> {
    await mutate(id, (row) => {
        row.image_path = imagePath;
        row.image_bytes = null;
        row.image_mime = '';
    });
}

/** Mark the submit delivered: bind the server job id, drop bytes, and leave the review screen a client→server mapping. */
export async function markEstimateSubmitted(id: string, serverJobId: string, when: string = Temporal.Now.instant().toString()): Promise<void> {
    await mutate(id, (row) => {
        row.status = 'submitted';
        row.server_job_id = serverJobId;
        row.submitted_at = when;
        row.image_bytes = null;
        row.image_mime = '';
    });
}

export async function deleteEstimateSubmit(id: string): Promise<void> {
    const db = await getDb();
    const tx = db.transaction(STORE, 'readwrite');
    tx.objectStore(STORE).delete(id);
    await awaitTx(tx);
}

/** Test-only: close the cached DB so a fresh `indexedDB` global can be substituted between tests. */
export function resetEstimateSubmitStoreForTests(): void {
    if (dbPromise) {
        void dbPromise.then((db) => db.close()).catch(() => undefined);
    }
    dbPromise = null;
}

export const ESTIMATE_SUBMIT_SYNC_TAG = 'push-estimate-submits';
